local LGpBaseMgr = LxRequire("LApp.gameplay.Base.LGpBaseMgr")
---@class LBlockMiniGameManager: LGpBaseMgr
local LBlockMiniGameManager = LxClass("LBlockMiniGameManager", LGpBaseMgr)


local LBlockMiniGameConst    = LXImport(".LBlockMiniGameConst")
local LBlockMiniGameObjsCtrl = LXImport(".Ctrl.LBlockMiniGameObjsCtrl")
local LFightIdleHudCtrl         = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleHudCtrl")
local LFightIdleHudData         = LxRequire("LApp.gameplay.fightIdle.Data.LFightIdleHudData")

function LBlockMiniGameManager:LBlockMiniGameManager()
    -- LBlockMiniGameMap
    ---@type LBlockMiniGameMap
    self._map = nil

    -- 对象控制类
    self._objsCtrl = nil

    self._hubObjIndexList = {}

    self._checkTime = 0

    self._hudScale = Vector3(0.75, 0.75, 0.75)
end

function LBlockMiniGameManager:Destroy()
    LGpBaseMgr.Destroy(self)

    if self._objsCtrl then
        self._objsCtrl:Destroy()
        self._objsCtrl = nil
    end
    if self._hudCtrl then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end
end

-- 进入地图
function LBlockMiniGameManager:EnterMap(map)
    self._map = map

    self:InitEvents()
    self:CreateCtrl()
end

-- 退出地图
function LBlockMiniGameManager:ExitMap()
    if self._objsCtrl then
        self._objsCtrl:Destroy()
        self._objsCtrl = nil
    end
    if self._hudCtrl then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end
    self._hubObjIndexList = {}
end

-- 初始事件
function LBlockMiniGameManager:InitEvents()
    self:EventRecv(EventNames.BLOCKMINIGAME_RESTART, function() self:OnReStart() end)
end

-- 控制类
function LBlockMiniGameManager:CreateCtrl()
    self._objsCtrl = LBlockMiniGameObjsCtrl:New(self, self._map)
    self._hudCtrl = LFightIdleHudCtrl:New(self)
    self._hudCtrl:InitHud()
end

-- 重新开始
function LBlockMiniGameManager:OnReStart()
    if self._objsCtrl then
        self._objsCtrl:Destroy()
        self._objsCtrl = nil
    end
    if self._hudCtrl then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end
    self:CreateCtrl()
    self:StartGame()
end

-- 开始游戏
function LBlockMiniGameManager:StartGame()
    self._hubObjIndexList = {}
    if self._objsCtrl then
        self._objsCtrl:StartGame()
    end
end

-- 生产士兵
function LBlockMiniGameManager:SpawnSelfObjs(dpList)
    if self._objsCtrl then
        self._objsCtrl:SpawnSelfObjs(dpList)
    end
end

-- 伤害飘字
function LBlockMiniGameManager:ApplyHurt(obj, hurt, changeType)
    if not self._hudCtrl then return end

    self:CheckHurtIndex()

    local hudDataList = self:CalcHurtWaveData(changeType, hurt, obj)

    self._hudCtrl:CreateHud(obj, hudDataList)
end

-- 组织 飘字数据结构
function LBlockMiniGameManager:GenerateHudData(obj,changeType, hurt, delay, floatHurtY, floatHurtXMin, floatHurtXMax)
    local data = LFightIdleHudData:New(changeType, hurt, delay, floatHurtY, floatHurtXMin, floatHurtXMax)

    if not self._hubObjIndexList[obj] then
        local list = {}
        list[0] = 1
        list[1] = 1
        self._hubObjIndexList[obj] = list
    elseif #self._hubObjIndexList[obj] > 8 then
        local list = {}
        list[0] = 1
        list[1] = 1
        self._hubObjIndexList[obj] = list
    else
        table.insert(self._hubObjIndexList[obj], 1)
    end

    data:SetIndex(#self._hubObjIndexList[obj])
    data:SetScale(self._hudScale)

    return data
end

-- 组织 飘字数据结构
function LBlockMiniGameManager:CalcHurtWaveData(changeType, hurt, obj)
    local offsetY = 0
    if obj:IsTower() and obj:IsSelf() then
        offsetY = 25
    end
    return { self:GenerateHudData(obj, changeType, hurt, 0, offsetY, -20, 20) }
end

function LBlockMiniGameManager:GetTime()
    return Time.time
end

-- update
function LBlockMiniGameManager:Update(dt)
    if self._objsCtrl then
        self._objsCtrl:Update(dt)
    end

    if self._hudCtrl then
        self._hudCtrl:OnRun(Time.time)
    end

    for k, v in pairs(self._hubObjIndexList) do
        v[0] = v[0] - dt
        if v[0] < 0 then
            self._hubObjIndexList[k] = nil
        end
    end

    if not self._freeTimeCount then
        self._freeTimeCount = Time.realtimeSinceStartup
    else
        local nowTime = Time.realtimeSinceStartup - self._freeTimeCount
        if nowTime > 120 then
            LxResUtil.RunUnusedAssetUnload()
            self._freeTimeCount = Time.realtimeSinceStartup
        end
    end
end

-- 清理列表，防止列表过大
function LBlockMiniGameManager:CheckHurtIndex()
    if self._checkTime < os.time() then
        self._checkTime = os.time() + 10

        local list = {}
        for k, v in pairs(self._hubObjIndexList) do
            list[k] = v
        end
        self._hubObjIndexList = list
    end
end

function LBlockMiniGameManager:GetUIBgTrans()
    if not self._map then return end
    local root = self._map:GetMapTrans()
    return CS.FindTrans(root, "LayerRoot/LayerBg/uiBg")
end


function LBlockMiniGameManager:GetUINodeTrans()
    local uiBg = self:GetUIBgTrans()
    if not uiBg then return end
    return CS.FindTrans(uiBg, "uiNode")
end

function LBlockMiniGameManager:GetUITitleTrans()
    local uiBg = self:GetUIBgTrans()
    if not uiBg then return end
    return CS.FindTrans(uiBg, "uiTitle")
end

return LBlockMiniGameManager
